  ('social-worker-moex-07980', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '少子老化影響到我國社會、經濟、政治各方面的發展，尤其是對社會福利的發展更甚，如套用 Howard Leichter的四項因素，其應屬於何種因素？', '["情境因素", "結構因素", "文化因素", "環境因素"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "70c57bb48ee5", "answer_pdf_sha1": "4f4489e8c0c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07981', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列對於費邊社（Fabian Society）的描述何者有誤？', '["成立於1884年", "認為國家應在政策面對貧窮有所介入，且提供社會保護（障）以對抗整體的社會問題", "影響英國工黨的成立", "主張用階級革命解決不公平的問題"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "70c57bb48ee5", "answer_pdf_sha1": "4f4489e8c0c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07982', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社會工作師若違反社會工作師法第14條「受主管機關或司法警察機關詢問時不得為虛偽之陳述或報告」， 及第 條「對於因業務而知悉或持有他人之秘密不得無故洩漏」，違者，處新台幣多少之罰鍰？ 15', '["二萬元以上十萬元以下", "二萬元以上十五萬元以下", "三萬元以上十萬元以下", "三萬元以上十五萬元以下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "70c57bb48ee5", "answer_pdf_sha1": "4f4489e8c0c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07983', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依特殊境遇家庭扶助條例中，符合第4條第1項第3款的對象「家庭暴力受害者」，若無力負擔訴訟費 用者得申請法律訴訟補助，其標準最高金額以新台幣多少元為限？', '["四萬元", "五萬元", "六萬元", "七萬元"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "70c57bb48ee5", "answer_pdf_sha1": "4f4489e8c0c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07984', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關家庭照顧假，例如：若員工的家庭成員或小孩需打 H1N1 的疫苗，員工須親自照顧時，得請家庭照 顧假，類似這樣的家庭照顧假，一個員工全年總日數以幾天為限？', '["三天", "五天", "七天", "十天"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "70c57bb48ee5", "answer_pdf_sha1": "4f4489e8c0c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07985', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關兒童及少年收養事件，下列的描述何者是錯誤的？', '["應基於兒童及少年之最佳利益", "滿七歲之兒童及少年被收養時，其意願以法院的判決為主", "法院認可兒童及少年被收養前，得准收養人與兒童及少年先行共同生活一段期間，供法院決定認可之 參考", "法院認可兒童及少年之收養前，應命主管機關或兒童及少年福利機構進行訪視，提出調查報告及建議"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "70c57bb48ee5", "answer_pdf_sha1": "4f4489e8c0c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
